<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #f4f6f9; color: #222; padding: 20px; max-width: 800px; margin: 0 auto; }
  h1 { text-align: center; margin-bottom: 20px; font-size: 1.6rem; }
  h2 { font-size: 1.1rem; margin-bottom: 10px; }
  section { background: #fff; border-radius: 8px; padding: 18px; margin-bottom: 16px; box-shadow: 0 1px 4px rgba(0,0,0,0.08); }
  label { display: block; font-weight: 600; margin-bottom: 4px; font-size: 0.9rem; }
  input, select { width: 100%; padding: 8px 10px; border: 1px solid #ccc; border-radius: 5px; font-size: 0.95rem; margin-bottom: 12px; }
  input:focus, select:focus { outline: none; border-color: #4a90d9; box-shadow: 0 0 0 2px rgba(74,144,217,0.2); }
  button { cursor: pointer; border: none; border-radius: 5px; font-size: 0.95rem; padding: 9px 18px; }
  #add-expense { background: #4a90d9; color: #fff; width: 100%; font-weight: 600; }
  #add-expense:hover { background: #3a7bc8; }
  #form-error { color: #c0392b; font-size: 0.88rem; min-height: 1.2em; margin-bottom: 8px; }
  .filters-row { display: flex; gap: 12px; flex-wrap: wrap; }
  .filters-row > div { flex: 1; min-width: 140px; }
  table { width: 100%; border-collapse: collapse; margin-top: 8px; }
  th, td { text-align: left; padding: 10px 8px; border-bottom: 1px solid #eee; font-size: 0.92rem; }
  th { background: #f8f9fa; font-weight: 600; position: sticky; top: 0; }
  .exp-del { background: #e74c3c; color: #fff; padding: 4px 10px; font-size: 0.82rem; border-radius: 4px; }
  .exp-del:hover { background: #c0392b; }
  .expense:nth-child(even) { background: #fafbfc; }
  #total { font-size: 1.25rem; font-weight: 700; color: #2c3e50; }
  .cat-summary { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 10px; }
  .cat-total { background: #eaf2fb; border-radius: 6px; padding: 8px 14px; font-size: 0.9rem; font-weight: 600; }
  .empty-msg { text-align: center; color: #999; padding: 20px; font-size: 0.95rem; }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<section>
  <h2>Add Expense</h2>
  <form id="expense-form">
    <label for="amount">Amount</label>
    <input type="number" id="amount" step="0.01" placeholder="0.00">

    <label for="category">Category</label>
    <select id="category">
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>

    <label for="date">Date</label>
    <input type="date" id="date">

    <label for="note">Note (optional)</label>
    <input type="text" id="note" placeholder="What was it for?">

    <div id="form-error"></div>
    <button type="submit" id="add-expense">Add Expense</button>
  </form>
</section>

<!-- Filters -->
<section>
  <h2>Filters</h2>
  <div class="filters-row">
    <div>
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">all</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div>
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div>
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</section>

<!-- Summary -->
<section>
  <h2>Summary</h2>
  <div>Total: <span id="total">0.00</span></div>
  <div class="cat-summary" id="cat-summary"></div>
</section>

<!-- Expense List -->
<section>
  <h2>Expenses</h2>
  <table>
    <thead>
      <tr>
        <th>Date</th>
        <th>Category</th>
        <th>Amount</th>
        <th>Note</th>
        <th></th>
      </tr>
    </thead>
    <tbody id="expense-list"></tbody>
  </table>
  <div id="empty-msg" class="empty-msg" style="display:none;">No expenses yet.</div>
</section>

<script>
(function() {
  const STORAGE_KEY = 'expense_tracker_data';
  const categories = ['groceries', 'transport', 'bills', 'fun'];

  // DOM refs
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categoryInput = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const formError = document.getElementById('form-error');
  const expenseList = document.getElementById('expense-list');
  const totalEl = document.getElementById('total');
  const catSummaryEl = document.getElementById('cat-summary');
  const emptyMsg = document.getElementById('empty-msg');
  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  // Load expenses from localStorage
  let expenses = [];
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) expenses = JSON.parse(stored);
  } catch(e) {
    expenses = [];
  }

  function save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  function getFiltered() {
    const cat = filterCategory.value;
    const from = filterFrom.value;
    const to = filterTo.value;
    return expenses.filter(function(exp) {
      if (cat !== 'all' && exp.category !== cat) return false;
      if (from && exp.date < from) return false;
      if (to && exp.date > to) return false;
      return true;
    });
  }

  function render() {
    const filtered = getFiltered();
    // Sort newest first by date, then by id descending for same-date tiebreak
    filtered.sort(function(a, b) {
      if (b.date !== a.date) return b.date.localeCompare(a.date);
      return b.id - a.id;
    });

    expenseList.innerHTML = '';
    if (filtered.length === 0) {
      emptyMsg.style.display = 'block';
    } else {
      emptyMsg.style.display = 'none';
    }

    filtered.forEach(function(exp) {
      const tr = document.createElement('tr');
      tr.className = 'expense';
      tr.dataset.id = exp.id;

      const tdDate = document.createElement('td');
      tdDate.textContent = exp.date;
      tr.appendChild(tdDate);

      const tdCat = document.createElement('td');
      tdCat.textContent = exp.category;
      tr.appendChild(tdCat);

      const tdAmt = document.createElement('td');
      tdAmt.textContent = parseFloat(exp.amount).toFixed(2);
      tr.appendChild(tdAmt);

      const tdNote = document.createElement('td');
      tdNote.textContent = exp.note || '';
      tr.appendChild(tdNote);

      const tdDel = document.createElement('td');
      const delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.textContent = 'Delete';
      delBtn.addEventListener('click', function() {
        expenses = expenses.filter(function(e) { return e.id !== exp.id; });
        save();
        render();
      });
      tdDel.appendChild(delBtn);
      tr.appendChild(tdDel);

      expenseList.appendChild(tr);
    });

    // Update total
    let total = 0;
    filtered.forEach(function(exp) { total += parseFloat(exp.amount); });
    totalEl.textContent = total.toFixed(2);

    // Update category totals
    catSummaryEl.innerHTML = '';
    categories.forEach(function(cat) {
      let catTotal = 0;
      filtered.forEach(function(exp) {
        if (exp.category === cat) catTotal += parseFloat(exp.amount);
      });
      const div = document.createElement('div');
      div.className = 'cat-total';
      div.setAttribute('data-cat', cat);
      div.textContent = cat + ': ' + catTotal.toFixed(2);
      catSummaryEl.appendChild(div);
    });
  }

  // Form submission
  form.addEventListener('submit', function(e) {
    e.preventDefault();
    formError.textContent = '';

    const rawAmount = amountInput.value.trim();
    const amount = parseFloat(rawAmount);
    const category = categoryInput.value;
    const date = dateInput.value;
    const note = noteInput.value.trim();

    // Validation
    if (rawAmount === '' || isNaN(amount) || amount <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return;
    }
    if (!date) {
      formError.textContent = 'Please select a date.';
      return;
    }

    const newExpense = {
      id: Date.now(),
      amount: amount,
      category: category,
      date: date,
      note: note
    };

    expenses.push(newExpense);
    save();

    // Reset amount field and clear error
    amountInput.value = '';
    formError.textContent = '';

    render();
  });

  // Filter change listeners
  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  // Initial render
  render();
})();
</script>

</body>
</html>
